from typing import TypeVar
T = TypeVar('T')
class Calculator:
  def add(self, a: T, b: T) -> str:
    if isinstance(a, (int, float)) and isinstance(b, (int, float)):
      return str(a + b)
    elif isinstance(a, str) and isinstance(b, str):
      return f'{a}{b}'
    else:
      return 'Invalid operation'
  def subtract(self, a: T, b: T) -> str:
    if isinstance(a, (int, float)) and isinstance(b, (int, float)):
      return str(a - b)
    else:
      return 'Invalid operation'
  def multiply(self, a: T, b: T) -> str:
    if isinstance(a, (int, float)) and isinstance(b, (int, float)):
      return str(a * b)
    else:
      return 'Invalid operation'

import sys
def solve(s):
  calculator = Calculator()
  result = calculator.add(s.split(' ')[0], s.split(' ')[2])
  return result

if __name__ == '__main__':
  t = int(input())
  for _ in range(t):
    s = input()
    print(solve(s))
